"use client";

import React, { useRef, useState, useMemo, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { Text, Image, Float, MeshTransmissionMaterial, Environment, ContactShadows } from "@react-three/drei";
import * as THREE from 'three';
import { useTheme } from 'next-themes';

interface Course {
  id: string;
  title: string;
  category: string;
  previewImage?: string;
}

interface CourseCardProps {
  course: Course;
  index: number;
  total: number;
  onSelect: (id: string) => void;
  isDark: boolean;
  scrollX: number;
}

function CourseCard({ course, index, total, onSelect, isDark, scrollX }: CourseCardProps) {
  const meshRef = useRef<THREE.Group>(null);
  const [hovered, setHovered] = useState(false);
  
  const spacing = 6; // Space between cards
  const xPos = index * spacing + scrollX;

  useFrame((state, delta) => {
    if (meshRef.current) {
      // Linear Position
      meshRef.current.position.set(xPos, 0, 0);
      
      // Focus Scaling: Scale up as it nears the center (x=0)
      const distFromCenter = Math.abs(xPos);
      const focusFactor = Math.max(0, 1 - distFromCenter / 10); // Spans +/- 10 units
      const targetScale = 1 + (focusFactor * 0.4) + (hovered ? 0.1 : 0);
      
      meshRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), 0.1);

      // Suble Tilt & Elevation for 3D depth
      meshRef.current.rotation.y = THREE.MathUtils.lerp(meshRef.current.rotation.y, (xPos / 15), 0.1);
      meshRef.current.position.z = focusFactor * 2; // Move forward when centered
    }
  });

  return (
    <group 
      ref={meshRef}
      onPointerOver={() => setHovered(true)}
      onPointerOut={() => setHovered(false)}
      onClick={() => onSelect(course.id)}
    >
      {/* Glass Card Background */}
      <RoundedPlane args={[3.4, 5.2, 0.4]}>
        <MeshTransmissionMaterial
          backside
          samples={4}
          resolution={128}
          transmission={isDark ? 0.6 : 0.8}
          roughness={0}
          thickness={0.2}
          ior={1.2}
          chromaticAberration={0.05}
          anisotropy={0.1}
          distortion={0.1}
          color={hovered ? "#3b82f6" : (isDark ? "#0a0a0a" : "#ffffff")}
          metalness={isDark ? 0.1 : 0.0}
        />
      </RoundedPlane>

      {/* Course Image */}
      {course.previewImage && (
        <Image 
          url={course.previewImage} 
          transparent 
          opacity={hovered ? 1 : (isDark ? 0.4 : 0.6)}
          scale={[3.1, 4.8, 1]}
          position={[0, 0, 0.05]}
        />
      )}

      {/* Card Border/Accent */}
      <mesh position={[0, 0, -0.01]}>
        <shapeGeometry args={[useMemo(() => {
          const w = 3.5;
          const h = 5.3;
          const r = 0.45;
          const s = new THREE.Shape();
          s.moveTo(-w/2, -h/2+r); s.lineTo(-w/2, h/2-r); s.absarc(-w/2+r, h/2-r, r, Math.PI, Math.PI/2, true);
          s.lineTo(w/2-r, h/2); s.absarc(w/2-r, h/2-r, r, Math.PI/2, 0, true);
          s.lineTo(w/2, -h/2+r); s.absarc(w/2-r, -h/2+r, r, 0, -Math.PI/2, true);
          s.lineTo(-w/2+r, -h/2); s.absarc(-w/2+r, -h/2+r, r, -Math.PI/2, -Math.PI, true);
          return s;
        }, [])]} />
        <meshBasicMaterial color={isDark ? "#ffffff" : "#000000"} opacity={0.05} transparent />
      </mesh>

      {/* Text Overlay */}
      <Text
        position={[0, -2, 0.15]}
        fontSize={0.22}
        color={isDark ? "white" : "black"}
        maxWidth={2.8}
        textAlign="center"
      >
        {course.title.toUpperCase()}
      </Text>
      
      <Text
        position={[0, -2.6, 0.1]}
        fontSize={0.12}
        color="#3b82f6"
        letterSpacing={0.2}
      >
        {course.category.toUpperCase()}
      </Text>
    </group>
  );
}

// Helper for rounded plane
function RoundedPlane({ args = [1, 1, 0.1], ...props }) {
  const shape = useMemo(() => {
    const [w, h, r] = args;
    const s = new THREE.Shape();
    s.moveTo(-w / 2, -h / 2 + r);
    s.lineTo(-w / 2, h / 2 - r);
    s.absarc(-w / 2 + r, h / 2 - r, r, Math.PI, Math.PI / 2, true);
    s.lineTo(w / 2 - r, h / 2);
    s.absarc(w / 2 - r, h / 2 - r, r, Math.PI / 2, 0, true);
    s.lineTo(w / 2, -h / 2 + r);
    s.absarc(w / 2 - r, -h / 2 + r, r, 0, -Math.PI / 2, true);
    s.lineTo(-w / 2 + r, -h / 2);
    s.absarc(-w / 2 + r, -h / 2 + r, r, -Math.PI / 2, -Math.PI, true);
    return s;
  }, [args]);
  return (
    <mesh {...props}>
      <shapeGeometry args={[shape]} />
      {props.children}
    </mesh>
  );
}

function Carousel({ courses, onSelect, isDark }: { courses: Course[], onSelect: (id: string) => void, isDark: boolean }) {
  const [scrollX, setScrollX] = useState(0);
  const targetScrollX = useRef(0);
  const lastX = useRef(0);
  const isDragging = useRef(false);
  const velocity = useRef(0);
  const { viewport } = useThree();

  // Inertia and boundary logic
  useFrame((state, delta) => {
    if (!isDragging.current) {
      // Apply momentum
      velocity.current *= 0.95;
      targetScrollX.current += velocity.current;

      // Auto-centering or boundaries
      const maxScroll = 0;
      const minScroll = -(courses.length - 1) * 6;
      
      if (targetScrollX.current > maxScroll) {
        targetScrollX.current = THREE.MathUtils.lerp(targetScrollX.current, maxScroll, 0.1);
      } else if (targetScrollX.current < minScroll) {
        targetScrollX.current = THREE.MathUtils.lerp(targetScrollX.current, minScroll, 0.1);
      }
    }
    
    // Smooth lerp for actual scroll position
    setScrollX(THREE.MathUtils.lerp(scrollX, targetScrollX.current, 0.1));
  });

  const handlePointerDown = (e: any) => {
    isDragging.current = true;
    lastX.current = e.clientX || e.touches?.[0].clientX;
    velocity.current = 0;
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging.current) return;
    const x = e.clientX || e.touches?.[0].clientX;
    const diff = (x - lastX.current) * 0.05; // Sensitivity
    targetScrollX.current += diff;
    velocity.current = diff;
    lastX.current = x;
  };

  const handlePointerUp = () => {
    isDragging.current = false;
  };

  useEffect(() => {
    window.addEventListener('mousemove', handlePointerMove);
    window.addEventListener('mouseup', handlePointerUp);
    window.addEventListener('touchmove', handlePointerMove);
    window.addEventListener('touchend', handlePointerUp);
    return () => {
      window.removeEventListener('mousemove', handlePointerMove);
      window.removeEventListener('mouseup', handlePointerUp);
      window.removeEventListener('touchmove', handlePointerMove);
      window.removeEventListener('touchend', handlePointerUp);
    };
  }, []);

  return (
    <group onPointerDown={handlePointerDown}>
      {courses.map((course, idx) => (
        <CourseCard 
          key={course.id} 
          course={course} 
          index={idx} 
          total={courses.length} 
          onSelect={onSelect}
          isDark={isDark}
          scrollX={scrollX}
        />
      ))}
      <ContactShadows 
         position={[0, -6, -5]} 
         opacity={isDark ? 0.1 : 0.05} 
         scale={60} 
         blur={2.5} 
         far={20} 
      />
    </group>
  );
}

export function CourseGlobe({ courses, onSelect }: { courses: Course[], onSelect: (id: string) => void }) {
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === 'dark';

  return (
    <div className="w-full h-full relative cursor-grab active:cursor-grabbing">
      <Canvas camera={{ position: [0, 0, 15], fov: 35 }}>
        <Environment preset={isDark ? "night" : "warehouse"} />
        <ambientLight intensity={isDark ? 0.1 : 0.4} />
        <spotLight position={[10, 20, 10]} angle={0.15} penumbra={1} intensity={isDark ? 2 : 1} castShadow />
        <pointLight position={[20, 20, 20]} intensity={isDark ? 3 : 1.5} color="#ffffff" />
        <Carousel courses={courses} onSelect={onSelect} isDark={isDark} />
      </Canvas>
      
      <div className="absolute inset-x-0 bottom-24 flex justify-center pointer-events-none">
        <div className={`px-6 py-2 bg-background/20 backdrop-blur-md border border-border/10 rounded-full shadow-xl`}>
          <span className={`text-[10px] font-bold uppercase tracking-[0.6em] ${isDark ? 'text-white/30' : 'text-black/30'}`}>
            Swipe to Explore • Tap to Discover
          </span>
        </div>
      </div>
    </div>
  );
}
